Set-StrictMode -Version 2.0
function New-GodModeProofBundle { param([string]$Project='.',[string]$MissionId,[array]$Commands=@(),[array]$Files=@(),$BrowserValidation=$null,$LivePreview=$null,$WindowsRoute=$null) $h=@{}; foreach($f in $Files){ $h[$f]=Get-GodModeFileHash (Join-Path (Resolve-GodModeProjectPath $Project) $f) }; @{schema_version=1;mission_id=$MissionId;created_at=Get-GodModeIso;worktree_path='';git_diff_hash='';files_before_hashes=@{};files_after_hashes=$h;commands=$Commands;browser_validation=$BrowserValidation;live_preview=$LivePreview;windows_route=$WindowsRoute} }
function Save-GodModeProofBundle { param([string]$Project='.',[hashtable]$Proof) $r=Initialize-GodModeStructure $Project; $p=Join-GodModePath $r ("traces/proof-$($Proof.mission_id).json"); Write-GodModeJsonAtomic $p $Proof|Out-Null; $p }
